from ranges import parse_range_list


class ParseRangeListTests(unittest.TestCase):
    def test_valid_cases(self) -> None:
        cases = {
            "": [],
            "4": [4],
            "1,3-5,8": [1, 3, 4, 5, 8],
            "2-2": [2],
            "-2--1": [-2, -1],
        }
        for text, expected in cases.items():
            with self.subTest(text=text):
                self.assertEqual(parse_range_list(text), expected)

    def test_invalid_cases(self) -> None:
        for text in ("1,,2", "5-3", "1.5", "a", "1-"):
