function deferred<T>(): { promise: Promise<T>; resolve: (value: T) => void } {
  let resolve!: (value: T) => void;
  const promise = new Promise<T>((done) => { resolve = done; });
  return { promise, resolve };
}

async function testLoadPair(): Promise<void> {
  const first = deferred<string>();
  const second = deferred<string>();
  const calls: number[] = [];
  const loadOne = (id: number): Promise<string> => {
    calls.push(id);
    return id === 10 ? first.promise : second.promise;
  };

  const pending = loadPair([10, 20], loadOne);
  second.resolve("twenty");
  first.resolve("ten");
  const result = await pending;

  if (JSON.stringify(calls) !== JSON.stringify([10, 20])) throw new Error("wrong calls");
  if (JSON.stringify(result) !== JSON.stringify(["ten", "twenty"])) throw new Error("wrong order");
}

